// Sprint Codex Framework — camada compartilhada por Biblioteca,
// Bestiário e Museu (e qualquer catálogo "estilo códice" futuro).
// Puramente utilitário/genérico: nenhum dos três catálogos
// (`lib/library.ts`/`lib/bestiary.ts`/`lib/museum.ts`) foi alterado —
// só a lógica de busca/filtro que cada um duplicava virou uma função
// compartilhada aqui.

export interface CodexCategoryOption<TSlug extends string = string> {
  slug: TSlug;
  label: string;
  icon?: string;
}

export interface CodexFact {
  label: string;
  value: string;
}

// Busca genérica por texto — mesma regra já usada nos 3 sistemas antes
// desta Sprint: item bloqueado nunca combina com busca, string vazia
// combina com tudo.
export function matchesSearch(query: string, text: string, locked: boolean): boolean {
  const normalized = query.trim().toLowerCase();
  if (normalized === "") return true;
  if (locked) return false;
  return text.toLowerCase().includes(normalized);
}

// Filtro genérico de uma dimensão (categoria/tipo/status/ano/etc.) —
// `null` sempre significa "sem filtro nesta dimensão".
export function matchesOption<T>(selected: T | null, value: T): boolean {
  return selected === null || selected === value;
}

export function findCategory<TSlug extends string>(
  categories: CodexCategoryOption<TSlug>[],
  slug: TSlug,
): CodexCategoryOption<TSlug> | undefined {
  return categories.find((c) => c.slug === slug);
}

// Etapa "Ordenações" — infraestrutura pronta, ainda não consumida por
// nenhuma UI (nenhum dos 3 catálogos expõe um controle de ordenação
// hoje; adicionar um seria mudança visual/funcional, fora do escopo
// desta Sprint). Genérica o bastante para ordenar por qualquer campo
// comparável de qualquer catálogo futuro.
export type SortDirection = "asc" | "desc";

export function sortByField<T, K extends keyof T>(items: T[], field: K, direction: SortDirection = "asc"): T[] {
  const sorted = [...items].sort((a, b) => {
    const left = a[field];
    const right = b[field];
    if (left < right) return -1;
    if (left > right) return 1;
    return 0;
  });
  return direction === "asc" ? sorted : sorted.reverse();
}

// Etapa "Interfaces compartilhadas" — todo catálogo (Biblioteca,
// Bestiário, Museu) já converge para esta forma mínima antes de virar
// props do CodexReader/CodexCard: um ícone, um título, uma linha de
// meta-informação (autor, tipo, categoria+ano) e uma lista de fatos
// rápidos para o Reader.
export interface CodexEntrySummary {
  id: string;
  icon: string;
  title: string;
  meta: string;
  statusLabel: string;
  locked: boolean;
}
